package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.io.StringWriter;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;
import org.mockito.stubbing.Answer;

import java.lang.reflect.Constructor;
import java.lang.reflect.InvocationHandler;
import java.lang.reflect.Method;
import java.lang.reflect.Proxy;

class CSVFormatTest {

    private CSVFormat csvFormat;

    @BeforeEach
    void setUp() {
        csvFormat = CSVFormat.DEFAULT;
    }

    @Test
    void testFormat_withNormalValues() throws IOException {
        String result = csvFormat.format("a", "b", "c");
        assertEquals("a,b,c", result);
    }

    @Test
    void testFormat_withEmptyValues() throws IOException {
        String result = csvFormat.format();
        assertEquals("", result);
    }

    @Test
    void testFormat_withNullValues() throws IOException {
        String result = csvFormat.format((Object) null);
        assertEquals("", result);
    }

    @Test
    void testFormat_trimsResult() throws IOException {
        String result = csvFormat.format(" a ", " b ");
        // The CSVPrinter adds quotes if necessary, but our format trims output
        assertEquals("\" a \",\" b \"", result);
    }

    @Test
    void testFormat_throwsIllegalStateExceptionOnIOException() throws Exception {
        // Use reflection and proxy to mock CSVPrinter constructor and behavior
        // Save original CSVFormat instance
        CSVFormat originalFormat = csvFormat;

        // Create a proxy CSVPrinter that throws IOException on printRecord
        Class<?> csvPrinterClass = CSVPrinter.class;

        // Create a proxy instance of CSVPrinter that throws IOException on printRecord
        Object proxyCSVPrinter = Proxy.newProxyInstance(
                csvPrinterClass.getClassLoader(),
                new Class<?>[]{csvPrinterClass},
                new InvocationHandler() {
                    @Override
                    public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                        if ("printRecord".equals(method.getName())) {
                            throw new IOException("forced IOException");
                        }
                        // For other methods, do nothing or return default
                        if (method.getReturnType().isPrimitive()) {
                            if (method.getReturnType() == boolean.class) return false;
                            if (method.getReturnType() == int.class) return 0;
                            if (method.getReturnType() == long.class) return 0L;
                            if (method.getReturnType() == float.class) return 0f;
                            if (method.getReturnType() == double.class) return 0d;
                            if (method.getReturnType() == byte.class) return (byte) 0;
                            if (method.getReturnType() == char.class) return (char) 0;
                            if (method.getReturnType() == short.class) return (short) 0;
                        }
                        return null;
                    }
                });

        // Use reflection to replace CSVFormat.format method's call to new CSVPrinter(...) with our proxy
        // Because CSVFormat.format creates new CSVPrinter(out, this), we need to mock CSVPrinter constructor
        // Since we cannot mock constructors easily without Mockito 4+, we will create a subclass of CSVFormat
        // that overrides format() to use our proxy printer

        CSVFormat csvFormatProxy = new CSVFormatProxy();

        IllegalStateException thrown = assertThrows(IllegalStateException.class, () -> {
            csvFormatProxy.format("x");
        });
        assertTrue(thrown.getCause() instanceof IOException);
        assertEquals("forced IOException", thrown.getCause().getMessage());
    }

    // Subclass CSVFormat to override format to use proxy CSVPrinter
    private static class CSVFormatProxy extends CSVFormat {
        private static final long serialVersionUID = 1L;

        CSVFormatProxy() {
            super(
                    CSVFormat.DEFAULT.getDelimiter(),
                    CSVFormat.DEFAULT.getQuoteCharacter(),
                    CSVFormat.DEFAULT.getQuoteMode(),
                    CSVFormat.DEFAULT.getCommentMarker(),
                    CSVFormat.DEFAULT.getEscapeCharacter(),
                    CSVFormat.DEFAULT.getIgnoreSurroundingSpaces(),
                    CSVFormat.DEFAULT.getIgnoreEmptyLines(),
                    CSVFormat.DEFAULT.getRecordSeparator(),
                    CSVFormat.DEFAULT.getNullString(),
                    CSVFormat.DEFAULT.getHeader(),
                    CSVFormat.DEFAULT.getSkipHeaderRecord(),
                    CSVFormat.DEFAULT.getAllowMissingColumnNames()
            );
        }

        @Override
        public String format(final Object... values) {
            final StringWriter out = new StringWriter();
            try {
                // Create proxy CSVPrinter that throws IOException on printRecord
                CSVPrinter proxyPrinter = (CSVPrinter) Proxy.newProxyInstance(
                        CSVPrinter.class.getClassLoader(),
                        new Class<?>[]{CSVPrinter.class},
                        new InvocationHandler() {
                            @Override
                            public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                                if ("printRecord".equals(method.getName())) {
                                    throw new IOException("forced IOException");
                                }
                                if (method.getReturnType().isPrimitive()) {
                                    if (method.getReturnType() == boolean.class) return false;
                                    if (method.getReturnType() == int.class) return 0;
                                    if (method.getReturnType() == long.class) return 0L;
                                    if (method.getReturnType() == float.class) return 0f;
                                    if (method.getReturnType() == double.class) return 0d;
                                    if (method.getReturnType() == byte.class) return (byte) 0;
                                    if (method.getReturnType() == char.class) return (char) 0;
                                    if (method.getReturnType() == short.class) return (short) 0;
                                }
                                return null;
                            }
                        });

                // Use reflection to call CSVPrinter's constructor with (Appendable, CSVFormat)
                // but we don't need to create real CSVPrinter since we have proxy
                // Instead, just call printRecord on proxy
                proxyPrinter.printRecord(values);
                return out.toString().trim();
            } catch (final IOException e) {
                throw new IllegalStateException(e);
            }
        }
    }
}
